按下鍵盤左右鍵切換模型

  import * as THREE from 'https://threejsfundamentals.org/threejs/resources/threejs/r127/build/three.module.js';
  import {OrbitControls} from 'https://threejsfundamentals.org/threejs/resources/threejs/r127/examples/jsm/controls/OrbitControls.js';
  import {GLTFLoader} from 'https://threejsfundamentals.org/threejs/resources/threejs/r127/examples/jsm/loaders/GLTFLoader.js';

  const canvas = document.querySelector('#c');
  canvas.addEventListener('keydown', (e) => {
    if (e.keyCode == 37) {
        index = (index + models.length - 1) % models.length;
        loadModel();
    } else if (e.keyCode == 39) {
        index = (index + 1) % models.length;
        loadModel();
    }
  });
  const renderer = new THREE.WebGLRenderer({canvas});
  renderer.setSize(canvas.clientWidth, canvas.clientHeight);

  const fov = 45;
  const aspect = canvas.clientWidth / canvas.clientHeight;
  const near = 0.1;
  const far = 100;
  const camera = new THREE.PerspectiveCamera(fov, aspect, near, far);
  camera.position.set(1, 1, 3);

  const controls = new OrbitControls(camera, canvas);

  const clock = new THREE.Clock();

  const scene = new THREE.Scene();
  scene.background = new THREE.Color(0xB3DDD5);

  // {
  //   const skyColor = 0xB1E1FF;
  //   const groundColor = 0xB97A20;
  //   const intensity = 1;
  //   const light = new THREE.HemisphereLight(skyColor, groundColor, intensity);
  //   scene.add(light);
  // }

  // {
  //   const color = 0xFFFFFF;
  //   const intensity = 1;
  //   const light = new THREE.DirectionalLight(color, intensity);
  //   light.position.set(5, 10, 2);
  //   scene.add(light);
  //   scene.add(light.target);
  // }

  {
    const color = 0xFFFFFF;
    const intensity = 1;
    const light = new THREE.AmbientLight(color, intensity);
    scene.add(light);
  }

  const models = ['Finn', 'Jake', 'PB', 'Spear', 'tree sword'];
  let index = 0;
  let root;
  let mixer;
  const gltfLoader = new GLTFLoader();

  function loadModel() {
    if (root) {
      scene.remove(root);
    }
    gltfLoader.load(`/assets/${models[index]}.glb`, (gltf) => {
      root = gltf.scene;
      scene.add(root);

      // compute the box that contains all the stuff
      // from root and below
      const box = new THREE.Box3().setFromObject(root);

      const boxSize = box.getSize(new THREE.Vector3()).length();
      const boxCenter = box.getCenter(new THREE.Vector3());

      // update the Trackball controls to handle the new size
      controls.maxDistance = boxSize * 10;
      controls.target.copy(boxCenter);
      controls.update();

      mixer = new THREE.AnimationMixer(root);
      gltf.animations.forEach(function(clip) {
        mixer.clipAction(clip).play();
      });
    });
  }
  loadModel();

  function render() {
    if (mixer) {
      mixer.update(clock.getDelta());
    }
    renderer.render(scene, camera);
    requestAnimationFrame(render);
  }
  requestAnimationFrame(render);

可以用來模擬 Java 的 private 封裝特性。

function MyObject(name, size) &#123;    this._name = name;    this._size = size;    this.getSize = function() &#123; // 這邊建立了一個 Closure        return this._size;    &#125;&#125;var myObject = new MyObject(&quot;Justin&quot;, 20);alert(myObject.getSize());
每次用 new 建立 MyObject 實體時，都會建立一個新的函式物件，並讓 getSize() 參考，在程式中隱含建立一個 Closure，需注意資源綁定的問題。
function MyObject(name, size) &#123;    this._name = name;    this._size = size;&#125;MyObject.prototype.getSize = function() &#123;    return this._size;&#125;
可以避免產生 Closure，而要注意的是：prototype 可以在建構式到使用 new 呼叫之間修改。建構式被呼叫前，設定給 prototype 的東西才會被物件繼承。
MyObject.prototype.color = &quot;red&quot;;var obj1 = new MyObject(); // obj1.color 是 &quot;red&quot;MyObject.prototype.color = &quot;blue&quot;;MyObject.prototype.sound = &quot;Ah...&quot;;var obj2 = new MyObject(); // obj2.color 是 &quot;blue&quot;，obj2.sound 是 &quot;Ah...&quot;

紀錄開發上常遇到的問題，避免重複踩坑。

紀錄API請求和回應可使用寫好的套件 HttpLoggingInterceptor，參考https://github.com/square/okhttp/tree/master/okhttp-logging-interceptor
或自行實作。
public class LogInterceptor implements Interceptor &#123;    @Override    public Response intercept(Chain chain) throws IOException &#123;        Request request = chain.request();        String bodyString = bodyToString(request);        Log.d(&quot;Mike&quot;, String.format(&quot;[%X] Request to %s\n%s&quot;,                chain.hashCode(), request.url(), bodyString));        Response response;        try &#123;            response = chain.proceed(request);        &#125; catch (SocketTimeoutException e) &#123;            Log.d(&quot;Mike&quot;, String.format(&quot;[%X] Response timeout for %s&quot;,                    chain.hashCode(), request.url()));            throw e;        &#125;        ResponseBody responseBody = response.body();        String responseBodyString = responseBody.string();        Log.d(&quot;Mike&quot;, String.format(&quot;[%X] Response to %s(%d)\n%s&quot;,                chain.hashCode(), response.request().url(), response.code(), responseBodyString));        return response.newBuilder().body(                ResponseBody.create(responseBody.contentType(), responseBodyString.getBytes())).build();    &#125;    private String bodyToString(Request request) &#123;        try &#123;            Request copy = request.newBuilder().build();            Buffer buffer = new Buffer();            if (copy.body() != null) &#123;                copy.body().writeTo(buffer);                return buffer.readUtf8();            &#125;            return &quot;&quot;;        &#125; catch (IOException e) &#123;            return &quot;&quot;;        &#125;    &#125;&#125;

若要印出headers，可加上這段。
注意：不要使用response.headers().names()跑for each處理，例如回傳的Set-Cookie有兩個，但該寫法只會印出一個。
Headers headers = response.headers();for (int i = 0; i &lt; headers.size(); i++) &#123;    Log.d(&quot;Mike&quot;, headers.name(i) + &quot;: &quot; + headers.value(i));&#125;

請求加上token認證例如使用Google API需要獲得token後，才有權限使用。
public class TokenInterceptor implements Interceptor &#123;    @Override    public Response intercept(Chain chain) throws IOException &#123;        Request request = chain.request().newBuilder()                .header(&quot;Authorization&quot;, &quot;Bearer &quot; + token)                .build();        return chain.proceed(request);    &#125;&#125;

保持連線和Cookie參考https://stackoverflow.com/questions/36706795/how-to-keep-session-using-retrofit-okhttpclient
implementation &#x27;com.squareup.okhttp3:okhttp-urlconnection:4.9.3&#x27;

OkHttpClient.Builder httpBuilder = new OkHttpClient.Builder()        .cookieJar(new JavaNetCookieJar(new CookieManager()))        .build();

修改FieldMap使用情境是有多個API都要傳同個欄位和值，例如UUID或時間戳記。
使用下列方式可對所有API都加上該值；但若是遇到只有部分需要，則不適用。建議改用Builder類別包住Map操作，然後將常用的欄位寫成public的method。
參考https://stackoverflow.com/questions/56515769/okhttp3-interceptor-add-fields-to-request-body
public class FieldMapInterceptor implements Interceptor &#123;    @Override    public Response intercept(Chain chain) throws IOException &#123;        Request request = chain.request();        if (&quot;POST&quot;.equals(request.method()) &amp;&amp; request.body() instanceof FormBody) &#123;            FormBody.Builder bodyBuilder = new FormBody.Builder();            FormBody formBody = (FormBody) request.body();            for (int i = 0; i &lt; formBody.size(); i++) &#123;                bodyBuilder.addEncoded(formBody.encodedName(i), formBody.encodedValue(i));            &#125;            bodyBuilder.add(&quot;key&quot;, &quot;value&quot;);            request = request.newBuilder().post(bodyBuilder.build()).build();        &#125;        return chain.proceed(request);    &#125;&#125;

上送檔案(body為raw)以Google Photos API的uploads為例，參考 [Android] Retrofit應用 - Google Photos API
上送檔案(body為form-data)以工作上遇到的日誌上送為例。
public interface CustomAPI &#123;    @POST(&quot;Upload&quot;)    Call&lt;ResponseBody&gt; uploadLog(@Body RequestBody body);&#125;

public void uploadLog(String date, File zipFile) &#123;    Retrofit retrofit = new Retrofit.Builder()            .baseUrl(&quot;https://xxx/&quot;)            .addConverterFactory(GsonConverterFactory.create())            .build();    final RequestBody body = new MultipartBody.Builder()            .setType(MultipartBody.FORM)            .addFormDataPart(&quot;date&quot;, date)            .addFormDataPart(&quot;log&quot;, zipFile.getName(), RequestBody.create(null, zipFile))            .build();    retrofit.create(CustomAPI.class).uploadLog(body)            .enqueue(new Callback&lt;ResponseBody&gt;() &#123;                @Override                public void onResponse(Call&lt;ResponseBody&gt; call, Response&lt;ResponseBody&gt; response) &#123;                                    &#125;                @Override                public void onFailure(Call&lt;ResponseBody&gt; call, Throwable t) &#123;                &#125;            &#125;);&#125;

串接Google API遇到java.lang.IllegalArgumentException: Malformed URL以Google Photos API的mediaItems:batchCreate為例。因其使用gRPC轉碼語法，若直接使用會有問題，endpoint開頭加上.&#x2F;即可。
public interface PhotoAPI &#123;    @POST(&quot;./mediaItems:batchCreate&quot;)    Call&lt;BatchCreateMediaItemsResponse&gt; batchCreateMediaItems(@Body BatchCreateMediaItemsRequest request);&#125;

參考資料

https://developers.google.com/photos/library/reference/rest/v1/mediaItems/batchCreate?hl=zh-tw
https://stackoverflow.com/questions/54406788/retrofit-how-to-use-colon-in-url

